14	  withUserAgentSuffix,
15	} from '@ai-sdk/provider-utils';
16	import { OpenAIChatLanguageModel } from './chat/openai-chat-language-model';
17	import { OpenAIChatModelId } from './chat/openai-chat-options';
18	import { OpenAICompletionLanguageModel } from './completion/openai-completion-language-model';
19	import { OpenAICompletionModelId } from './completion/openai-completion-options';
20	import { OpenAIEmbeddingModel } from './embedding/openai-embedding-model';
21	import { OpenAIEmbeddingModelId } from './embedding/openai-embedding-options';
22	import { OpenAIImageModel } from './image/openai-image-model';
23	import { OpenAIImageModelId } from './image/openai-image-options';
24	import { openaiTools } from './openai-tools';
25	import { OpenAIResponsesLanguageModel } from './responses/openai-responses-language-model';
26	import { OpenAIResponsesModelId } from './responses/openai-responses-options';
27	import { OpenAISpeechModel } from './speech/openai-speech-model';
28	import { OpenAISpeechModelId } from './speech/openai-speech-options';
29	import { OpenAITranscriptionModel } from './transcription/openai-transcription-model';
30	import { OpenAITranscriptionModelId } from './transcription/openai-transcription-options';
31	import { VERSION } from './version';
32	
33	export interface OpenAIProvider extends ProviderV3 {
34	  (modelId: OpenAIResponsesModelId): LanguageModelV3;
