### src/<provider>-provider.ts - Factory Function
**Path:** `/packages/fal/src/fal-provider.ts` | `/packages/openai/src/openai-provider.ts`

Key patterns:

1. **Provider Settings Interface** - accepts baseURL, apiKey, headers, fetch
2. **Provider Interface** - extends ProviderV3 with model creation methods
3. **API Key Loading** - checks environment variables with fallback
4. **Factory Function** - `createFal(options): FalProvider`
5. **Default Export** - `export const fal = createFal()`

Example structure (FAL):
```typescript
export interface FalProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface FalProvider extends ProviderV3 {
  image(modelId: FalImageModelId): ImageModelV3;
  imageModel(modelId: FalImageModelId): ImageModelV3;
  transcription(modelId: FalTranscriptionModelId): TranscriptionModelV3;
  video(modelId: FalVideoModelId): Experimental_VideoModelV3;
  speech(modelId: FalSpeechModelId): SpeechModelV3;
}

export function createFal(options: FalProviderSettings = {}): FalProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Key ${loadFalApiKey({ apiKey: options.apiKey })}`,
        ...options.headers,
      },
      `ai-sdk/fal/${VERSION}`,
    );

  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    speech: createSpeechModel,
    transcription: createTranscriptionModel,
    video: createVideoModel,
    videoModel: createVideoModel,
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
  };
}

export const fal = createFal();
```

