FAL example (simplified):
```typescript
import {
  ImageModelV3,
  SharedV3Warning,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import {
  combineHeaders,
  convertImageModelFileToDataUri,
  createJsonResponseHandler,
  postJsonToApi,
  parseProviderOptions,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface FalImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class FalImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: FalImageModelId,
    private readonly config: FalImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const warnings: Array<SharedV3Warning> = [];

    const falOptions = await parseProviderOptions({
      provider: 'fal',
      providerOptions: options.providerOptions,
      schema: falImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      prompt: options.prompt,
      seed: options.seed,
      num_images: options.n,
    };

    // Handle image files and mask
    if (options.files != null && options.files.length > 0) {
      requestBody.image_url = convertImageModelFileToDataUri(options.files[0]);
    }

    if (options.mask != null) {
      requestBody.mask_url = convertImageModelFileToDataUri(options.mask);
    }

    // Merge provider-specific options
    if (falOptions) {
      const fieldMapping: Record<string, string> = {
        guidanceScale: 'guidance_scale',
        numInferenceSteps: 'num_inference_steps',
        // ... etc
      };

      for (const [key, value] of Object.entries(falOptions)) {
        const apiKey = fieldMapping[key] ?? key;
        if (value !== undefined) {
          requestBody[apiKey] = value;
        }
      }
    }

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/${this.modelId}`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: requestBody,
      failedResponseHandler: falFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        falImageResponseSchema,
      ),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // Download images and process response
    const downloadedImages = await Promise.all(
      value.images.map(image =>
        this.downloadImage(image.url, options.abortSignal),
      ),
    );

    return {
      images: downloadedImages,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: new Date(),
        headers: responseHeaders,
      },
      providerMetadata: {
        fal: {
          images: value.images,
          // ... other metadata
        },
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value: response } = await getFromApi({
      url,
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return response;
  }
}

// Validation schemas
const falImageSchema = z.object({
  url: z.string(),
  width: z.number().nullish(),
  height: z.number().nullish(),
});

const commonResponseSchema = z.object({
  timings: z.object({ inference: z.number().optional() }).optional(),
  seed: z.number().optional(),
  has_nsfw_concepts: z.array(z.boolean()).optional(),
  prompt: z.string().optional(),
});

const falImageResponseSchema = z
  .union([
    z.object({ images: z.array(falImageSchema) }),
    z.object({ image: falImageSchema }),
  ])
  .transform(v => ('images' in v ? v : { ...v, images: [v.image] }));

const falFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: z.object({
    message: z.string(),
  }),
  errorToMessage: error => error.message ?? 'Unknown error',
});
```

