export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The rendering style of the pixel art image.
         * - `pixel`: Classic pixel art style with sharp, blocky pixels.
         * - `retro`: Retro-inspired style with limited color palettes.
         * - `8bit`: Classic 8-bit video game aesthetic.
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The pixel density (size of each pixel block) in the output image.
         * Higher values produce a coarser, more pixelated look.
         * Valid range: 1–32 (pixels per block).
         * @default 8
         */
        pixelDensity: z.number().int().min(1).max(32).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

