  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      prompt,
      n,
      seed,
    };

    // Map standard size parameter (e.g. "512x512") to width/height
    if (size != null) {
      const [width, height] = size.split('x').map(Number);
      requestBody.width = width;
      requestBody.height = height;
    } else if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio directly. Use the `size` parameter instead.',
